class Solution {
public:
    vector<int> findSingleNumbers(vector<int>& nums) {
        int xorAll = 0;

        for (int x : nums) xorAll ^= x;

        int diffBit = xorAll & -xorAll;

        int num1 = 0, num2 = 0;

        for (int x : nums) {
            if (x & diffBit) num1 ^= x;
            else num2 ^= x;
        }

        if (num1 < num2) return {num1, num2};
        return {num2, num1};
    }
};

