code.C:
void findSingleNumbers(int *nums, int n, int *a, int *b) {
    unsigned int xor_all = 0;

    // Step 1: XOR all elements together (cast to unsigned to be safe with negatives)
    for (int i = 0; i < n; i++) {
        xor_all ^= (unsigned int)nums[i];
    }
    unsigned int rightmost_bit = xor_all & ~(xor_all - 1);

    unsigned int num1 = 0;
    unsigned int num2 = 0;

    // Step 3: Partition the numbers into two groups and XOR them
    for (int i = 0; i < n; i++) {
        if (((unsigned int)nums[i] & rightmost_bit) != 0) {
            num1 ^= (unsigned int)nums[i];
        } else {
            num2 ^= (unsigned int)nums[i];
        }
    }

    // Step 4: Cast back to signed integers and assign in ascending order
    int res1 = (int)num1;
    int res2 = (int)num2;

    if (res1 < res2) {
        *a = res1;
        *b = res2;
    } else {
        *a = res2;
        *b = res1;
    }
}

