class Solution {
    public int[] findSingleNumbers(int[] nums) {
        int xorAll = 0;

        // Step 1: XOR of all numbers
        for (int x : nums) {
            xorAll ^= x;
        }

        // Step 2: Rightmost set bit difference
        int diffBit = xorAll & -xorAll;

        int num1 = 0, num2 = 0;

        // Step 3: Partition numbers
        for (int x : nums) {
            if ((x & diffBit) != 0) num1 ^= x;
            else num2 ^= x;
        }

        int[] result = new int[] { num1, num2 };
        Arrays.sort(result);
        return result;
    }
}

