class Solution {
    findSingleNumbers(nums) {
        let xorAll = 0;

        // Step 1: XOR all numbers
        for (let x of nums) xorAll ^= x;

        // Step 2: Rightmost set bit
        let diffBit = xorAll & -xorAll;

        let num1 = 0, num2 = 0;

        // Step 3: Split into two groups
        for (let x of nums) {
            if (x & diffBit) num1 ^= x;
            else num2 ^= x;
        }

        return [num1, num2].sort((a, b) => a - b);
    }
}
